import '../serialization/navivox_json.dart';
import 'navivox_memory_degradation.dart';

enum NavivoxMemoryHealth { active, degraded, unavailable }

enum NavivoxMemoryType {
  all('all', 'All'),
  turns('turns', 'Turns'),
  memoryItems('memory_items', 'Memory items'),
  observations('observations', 'Observations'),
  conclusions('conclusions', 'Conclusions'),
  sessionSummaries('session_summaries', 'Session summaries'),
  entities('entities', 'Entities'),
  relationships('relationships', 'Relationships');

  const NavivoxMemoryType(this.wireValue, this.label);

  final String wireValue;
  final String label;

  static NavivoxMemoryType fromWire(Object? value) {
    return navivoxValueFromWire(
      value: value,
      values: values,
      wireValue: (type) => type.wireValue,
      fallback: all,
    );
  }
}

enum NavivoxMemoryActionType {
  pin('pin', 'Pin'),
  unpin('unpin', 'Unpin'),
  archive('archive', 'Archive'),
  unarchive('unarchive', 'Unarchive'),
  markStale('mark_stale', 'Mark stale'),
  addCorrection('add_correction', 'Add correction');

  const NavivoxMemoryActionType(this.wireValue, this.label);

  final String wireValue;
  final String label;

  static NavivoxMemoryActionType fromWire(Object? value) {
    return navivoxValueFromWire(
      value: value,
      values: values,
      wireValue: (type) => type.wireValue,
      fallback: archive,
    );
  }
}

class NavivoxMemorySearchResult {
  const NavivoxMemorySearchResult({
    required this.items,
    this.nextPageToken = '',
    this.degradedReason = '',
  });

  const NavivoxMemorySearchResult.degraded({required String reason})
    : items = const [],
      nextPageToken = '',
      degradedReason = reason;

  factory NavivoxMemorySearchResult.fromJson(Map<String, Object?> json) {
    return NavivoxMemorySearchResult(
      items: navivoxMapListFromJson(
        json['items'],
      ).map(NavivoxMemoryItem.fromJson).toList(growable: false),
      nextPageToken: navivoxStringFromJson(
        json['next_page_token'],
        fallback: '',
      ),
      degradedReason: navivoxMemoryDegradedReasonFromJson(json),
    );
  }

  final List<NavivoxMemoryItem> items;
  final String nextPageToken;
  final String degradedReason;

  bool get isDegraded => navivoxMemoryIsDegraded(degradedReason);
}

class NavivoxMemoryItem {
  const NavivoxMemoryItem({
    required this.id,
    required this.type,
    required this.snippet,
    this.timestamp = '',
    this.sessionId = '',
    this.peerId = '',
    this.status = '',
    this.tags = const [],
    this.score,
  });

  factory NavivoxMemoryItem.fromJson(Map<String, Object?> json) {
    return NavivoxMemoryItem(
      id: navivoxStringFromJson(json['id'], fallback: ''),
      type: NavivoxMemoryType.fromWire(json['type']),
      snippet: navivoxStringFromJson(
        json['snippet'] ?? json['content'],
        fallback: '',
      ),
      timestamp: navivoxStringFromJson(
        json['timestamp'] ?? json['created_at'],
        fallback: '',
      ),
      sessionId: navivoxStringFromJson(
        json['session_id'] ?? json['session_key'],
        fallback: '',
      ),
      peerId: navivoxStringFromJson(json['peer_id'], fallback: ''),
      status: navivoxStringFromJson(json['status'], fallback: ''),
      tags: navivoxStringListFromJson(json['tags']),
      score: navivoxDoubleFromJson(json['score']),
    );
  }

  final String id;
  final NavivoxMemoryType type;
  final String snippet;
  final String timestamp;
  final String sessionId;
  final String peerId;
  final String status;
  final List<String> tags;
  final double? score;
}

class NavivoxMemoryDetail {
  const NavivoxMemoryDetail({
    required this.id,
    required this.type,
    required this.content,
    this.source = '',
    this.sessionId = '',
    this.peerId = '',
    this.createdAt = '',
    this.updatedAt = '',
    this.status = '',
    this.tags = const [],
    this.provenance = '',
    this.linkedEntities = const [],
    this.linkedRelationships = const [],
    this.degradedReason = '',
  });

  const NavivoxMemoryDetail.degraded({required this.id, required String reason})
    : type = NavivoxMemoryType.all,
      content = '',
      source = '',
      sessionId = '',
      peerId = '',
      createdAt = '',
      updatedAt = '',
      status = '',
      tags = const [],
      provenance = '',
      linkedEntities = const [],
      linkedRelationships = const [],
      degradedReason = reason;

  factory NavivoxMemoryDetail.fromJson(Map<String, Object?> json) {
    return NavivoxMemoryDetail(
      id: navivoxStringFromJson(json['id'], fallback: ''),
      type: NavivoxMemoryType.fromWire(json['type']),
      content: navivoxStringFromJson(
        json['content'] ?? json['snippet'],
        fallback: '',
      ),
      source: navivoxStringFromJson(
        json['source'] ?? json['source_table'],
        fallback: '',
      ),
      sessionId: navivoxStringFromJson(
        json['session_id'] ?? json['session_key'],
        fallback: '',
      ),
      peerId: navivoxStringFromJson(json['peer_id'], fallback: ''),
      createdAt: navivoxStringFromJson(
        json['created_at'] ?? json['timestamp'],
        fallback: '',
      ),
      updatedAt: navivoxStringFromJson(json['updated_at'], fallback: ''),
      status: navivoxStringFromJson(json['status'], fallback: ''),
      tags: navivoxStringListFromJson(json['tags']),
      provenance: navivoxStringFromJson(json['provenance'], fallback: ''),
      linkedEntities: navivoxStringListFromJson(json['linked_entities']),
      linkedRelationships: navivoxStringListFromJson(
        json['linked_relationships'],
      ),
      degradedReason: navivoxMemoryDegradedReasonFromJson(json),
    );
  }

  final String id;
  final NavivoxMemoryType type;
  final String content;
  final String source;
  final String sessionId;
  final String peerId;
  final String createdAt;
  final String updatedAt;
  final String status;
  final List<String> tags;
  final String provenance;
  final List<String> linkedEntities;
  final List<String> linkedRelationships;
  final String degradedReason;

  bool get isDegraded => navivoxMemoryIsDegraded(degradedReason);
}

class NavivoxMemoryActionResult {
  const NavivoxMemoryActionResult({
    required this.accepted,
    required this.action,
    required this.message,
    this.rawSourcePreserved = true,
    this.degradedReason = '',
  });

  const NavivoxMemoryActionResult.degraded({
    required this.action,
    required String reason,
  }) : accepted = false,
       message = '',
       rawSourcePreserved = true,
       degradedReason = reason;

  factory NavivoxMemoryActionResult.fromJson(Map<String, Object?> json) {
    return NavivoxMemoryActionResult(
      accepted: navivoxBoolFromJson(json['accepted']),
      action: NavivoxMemoryActionType.fromWire(json['action']),
      message: navivoxStringFromJson(json['message'], fallback: ''),
      rawSourcePreserved: navivoxBoolFromJson(
        json['raw_source_preserved'],
        fallback: true,
      ),
      degradedReason: navivoxMemoryDegradedReasonFromJson(json),
    );
  }

  final bool accepted;
  final NavivoxMemoryActionType action;
  final String message;
  final bool rawSourcePreserved;
  final String degradedReason;

  bool get isDegraded => navivoxMemoryIsDegraded(degradedReason);
}

class NavivoxMemoryOverview {
  const NavivoxMemoryOverview({
    required this.profileId,
    required this.workspaceId,
    required this.databaseLabel,
    required this.health,
    required this.totalTurns,
    required this.activeMemoryItems,
    required this.observations,
    required this.conclusions,
    required this.sessionSummaries,
    required this.entities,
    required this.relationships,
    this.degradedReason = '',
    this.lastUpdatedAt,
  });

  const NavivoxMemoryOverview.degraded({
    required this.profileId,
    required String reason,
  }) : workspaceId = '',
       databaseLabel = 'redacted',
       health = NavivoxMemoryHealth.degraded,
       totalTurns = 0,
       activeMemoryItems = 0,
       observations = 0,
       conclusions = 0,
       sessionSummaries = 0,
       entities = 0,
       relationships = 0,
       degradedReason = reason,
       lastUpdatedAt = null;

  factory NavivoxMemoryOverview.fromJson(Map<String, Object?> json) {
    final counts = json['counts'];
    final countMap = counts is Map ? navivoxMapFromJson(counts) : json;
    final healthText = navivoxOptionalStringFromJson(
      json['health'],
    )?.toLowerCase();
    final health = switch (healthText) {
      'active' || 'ok' || 'healthy' => NavivoxMemoryHealth.active,
      'unavailable' || 'offline' => NavivoxMemoryHealth.unavailable,
      _ => NavivoxMemoryHealth.degraded,
    };

    return NavivoxMemoryOverview(
      profileId: navivoxStringFromJson(json['profile_id'], fallback: 'default'),
      workspaceId: navivoxStringFromJson(json['workspace_id'], fallback: ''),
      databaseLabel: _safeDatabaseLabel(
        json['database_label'] ?? json['database_path'],
      ),
      health: health,
      totalTurns: navivoxIntFromJson(
        countMap['turns'] ?? countMap['total_turns'],
      ),
      activeMemoryItems: navivoxIntFromJson(
        countMap['memory_items'] ?? countMap['active_memory_items'],
      ),
      observations: navivoxIntFromJson(countMap['observations']),
      conclusions: navivoxIntFromJson(countMap['conclusions']),
      sessionSummaries: navivoxIntFromJson(countMap['session_summaries']),
      entities: navivoxIntFromJson(countMap['entities']),
      relationships: navivoxIntFromJson(countMap['relationships']),
      degradedReason: navivoxMemoryDegradedReasonFromJson(json),
      lastUpdatedAt: navivoxDateTimeFromJson(json['last_updated_at']),
    );
  }

  final String profileId;
  final String workspaceId;
  final String databaseLabel;
  final NavivoxMemoryHealth health;
  final int totalTurns;
  final int activeMemoryItems;
  final int observations;
  final int conclusions;
  final int sessionSummaries;
  final int entities;
  final int relationships;
  final String degradedReason;
  final DateTime? lastUpdatedAt;

  bool get isActive => health == NavivoxMemoryHealth.active;

  String get healthLabel => switch (health) {
    NavivoxMemoryHealth.active => 'Goncho active',
    NavivoxMemoryHealth.degraded => 'Goncho degraded',
    NavivoxMemoryHealth.unavailable => 'Goncho unavailable',
  };
}

String _safeDatabaseLabel(Object? value) {
  final text = navivoxOptionalStringFromJson(value);
  if (text == null) return 'redacted';

  const gormesMarker = '/.gormes/';
  final markerIndex = text.indexOf(gormesMarker);
  if (markerIndex >= 0) {
    return '~/.gormes/${text.substring(markerIndex + gormesMarker.length)}';
  }
  if (text.startsWith('/')) {
    final parts = text.split('/').where((part) => part.isNotEmpty).toList();
    final basename = parts.isEmpty ? 'memory.db' : parts.last;
    return 'redacted/$basename';
  }
  return text;
}

import '../identity/navivox_profile_contact_key.dart';
import '../voice/navivox_voice_status.dart';

enum NavivoxMessageKind {
  text,
  toolCall,
  voice,
  safetyWarning,
  approvalRequest,
}

enum NavivoxMessageAuthor { user, assistant, system }

class NavivoxChatMessage {
  const NavivoxChatMessage({
    required this.id,
    required this.author,
    required this.kind,
    required this.createdAt,
    this.text,
    this.toolCall,
    this.voice,
    this.safetyNotice,
    this.runRecordReference,
    this.serverId,
    this.profileId,
  });

  final String id;
  final NavivoxMessageAuthor author;
  final NavivoxMessageKind kind;
  final DateTime createdAt;
  final String? text;
  final NavivoxToolCall? toolCall;
  final NavivoxVoiceMessage? voice;
  final NavivoxSafetyNotice? safetyNotice;
  final String? runRecordReference;
  final String? serverId;
  final String? profileId;

  String? get profileContactKey => navivoxProfileContactKeyFromNullable(
    serverId: serverId,
    profileId: profileId,
  );
}

class NavivoxToolCall {
  const NavivoxToolCall({
    required this.name,
    required this.status,
    required this.summary,
    this.approval,
    this.artifacts = const [],
  });

  final String name;
  final String status;
  final String summary;
  final NavivoxToolApproval? approval;
  final List<NavivoxToolArtifact> artifacts;

  NavivoxToolCall copyWith({
    String? name,
    String? status,
    String? summary,
    NavivoxToolApproval? approval,
    List<NavivoxToolArtifact>? artifacts,
  }) {
    return NavivoxToolCall(
      name: name ?? this.name,
      status: status ?? this.status,
      summary: summary ?? this.summary,
      approval: approval ?? this.approval,
      artifacts: artifacts ?? this.artifacts,
    );
  }
}

class NavivoxToolApproval {
  const NavivoxToolApproval({
    required this.id,
    required this.status,
    required this.prompt,
    this.risk,
  });

  final String id;
  final String status;
  final String prompt;
  final String? risk;
}

class NavivoxToolArtifact {
  const NavivoxToolArtifact({
    required this.id,
    required this.kind,
    required this.title,
    this.summary,
    this.ref,
  });

  final String id;
  final String kind;
  final String title;
  final String? summary;
  final String? ref;
}

class NavivoxSafetyNotice {
  const NavivoxSafetyNotice({
    required this.id,
    required this.message,
    this.severity,
    this.risk,
    this.approvalId,
    this.toolCallId,
  });

  final String id;
  final String message;
  final String? severity;
  final String? risk;
  final String? approvalId;
  final String? toolCallId;
}

class NavivoxVoiceMessage {
  const NavivoxVoiceMessage({
    required this.duration,
    required this.transcript,
    required this.confidence,
    this.voiceRunId,
    this.status,
  });

  final String? voiceRunId;
  final Duration duration;
  final String transcript;
  final double confidence;
  final NavivoxVoiceRunStatus? status;
}

export 'navivox_voice_status.dart';

import 'navivox_voice_status.dart';

class NavivoxVoiceRun {
  const NavivoxVoiceRun({
    required this.id,
    required this.serverId,
    required this.profileId,
    required this.status,
    required this.transcriptSource,
    required this.ttsStatus,
    required this.createdAt,
    required this.updatedAt,
    this.sessionId,
    this.requestId,
    this.transcript,
    this.duration,
    this.confidence,
    this.reason,
    this.retentionPolicy = 'transcript_only',
  });

  factory NavivoxVoiceRun.recording({
    required String id,
    required String serverId,
    required String profileId,
    required DateTime createdAt,
  }) {
    return NavivoxVoiceRun(
      id: id,
      serverId: serverId,
      profileId: profileId,
      status: NavivoxVoiceRunStatus.recording,
      transcriptSource: NavivoxTranscriptSource.device,
      ttsStatus: NavivoxTtsStatus.unavailable,
      createdAt: createdAt,
      updatedAt: createdAt,
    );
  }

  final String id;
  final String serverId;
  final String profileId;
  final String? sessionId;
  final String? requestId;
  final NavivoxVoiceRunStatus status;
  final NavivoxTranscriptSource transcriptSource;
  final NavivoxTtsStatus ttsStatus;
  final String? transcript;
  final Duration? duration;
  final double? confidence;
  final String? reason;
  final String retentionPolicy;
  final DateTime createdAt;
  final DateTime updatedAt;

  bool get isTerminal => navivoxVoiceRunStatusIsTerminal(status);

  NavivoxVoiceRun withDeviceTranscript({
    required String transcript,
    required Duration duration,
    required double confidence,
    required DateTime updatedAt,
  }) {
    return copyWith(
      status: NavivoxVoiceRunStatus.pendingSend,
      transcriptSource: NavivoxTranscriptSource.device,
      transcript: transcript,
      duration: duration,
      confidence: confidence,
      updatedAt: updatedAt,
    );
  }

  NavivoxVoiceRun markSubmitted({
    required String requestId,
    String? sessionId,
  }) {
    return copyWith(
      status: NavivoxVoiceRunStatus.submitted,
      requestId: requestId,
      sessionId: sessionId,
    );
  }

  NavivoxVoiceRun markCompleted() {
    return copyWith(status: NavivoxVoiceRunStatus.completed);
  }

  NavivoxVoiceRun markCancelled(String reason) {
    return copyWith(status: NavivoxVoiceRunStatus.cancelled, reason: reason);
  }

  NavivoxVoiceRun markFailed(String reason) {
    return copyWith(status: NavivoxVoiceRunStatus.failed, reason: reason);
  }

  NavivoxVoiceRun copyWith({
    String? sessionId,
    String? requestId,
    NavivoxVoiceRunStatus? status,
    NavivoxTranscriptSource? transcriptSource,
    NavivoxTtsStatus? ttsStatus,
    String? transcript,
    Duration? duration,
    double? confidence,
    String? reason,
    String? retentionPolicy,
    DateTime? updatedAt,
  }) {
    return NavivoxVoiceRun(
      id: id,
      serverId: serverId,
      profileId: profileId,
      sessionId: sessionId ?? this.sessionId,
      requestId: requestId ?? this.requestId,
      status: status ?? this.status,
      transcriptSource: transcriptSource ?? this.transcriptSource,
      ttsStatus: ttsStatus ?? this.ttsStatus,
      transcript: transcript ?? this.transcript,
      duration: duration ?? this.duration,
      confidence: confidence ?? this.confidence,
      reason: reason ?? this.reason,
      retentionPolicy: retentionPolicy ?? this.retentionPolicy,
      createdAt: createdAt,
      updatedAt: updatedAt ?? this.updatedAt,
    );
  }
}

/// Shared voice-run status and media-state contracts.
///
/// Keep these enums separate from the full [NavivoxVoiceRun] record so
/// transcript, channel, and presentation layers can depend on status values
/// without importing the run value object.
enum NavivoxVoiceRunStatus {
  idle,
  recording,
  transcribing,
  pendingSend,
  submitted,
  serverProcessing,
  serverSttComplete,
  agentTurnRunning,
  ttsQueued,
  ttsReady,
  playing,
  completed,
  cancelled,
  failed,
}

enum NavivoxTranscriptSource { device, manual, server }

enum NavivoxTtsStatus { unavailable, queued, ready, playing, stopped, failed }

bool navivoxVoiceRunStatusIsTerminal(NavivoxVoiceRunStatus status) {
  return switch (status) {
    NavivoxVoiceRunStatus.completed ||
    NavivoxVoiceRunStatus.cancelled ||
    NavivoxVoiceRunStatus.failed => true,
    _ => false,
  };
}

/// Shared coercion helpers for Navivox wire-protocol JSON payloads.
///
/// These helpers intentionally accept loose `Object?` values because gateway and
/// memory endpoints can be decoded from typed maps, platform channels, or JSON
/// maps with dynamic keys.
String navivoxStringFromJson(Object? value, {required String fallback}) {
  final text = value?.toString().trim();
  if (text == null || text.isEmpty) return fallback;
  return text;
}

String? navivoxOptionalStringFromJson(Object? value) {
  final text = value?.toString().trim();
  if (text == null || text.isEmpty) return null;
  return text;
}

/// Returns a trimmed string only when [value] is already a literal string.
String? navivoxOptionalLiteralStringFromJson(Object? value) {
  if (value is! String) return null;
  final text = value.trim();
  return text.isEmpty ? null : text;
}

int navivoxIntFromJson(Object? value) {
  if (value is int) return value;
  if (value is num) return value.toInt();
  return int.tryParse(value?.toString() ?? '') ?? 0;
}

double? navivoxDoubleFromJson(Object? value) {
  if (value is double) return value;
  if (value is num) return value.toDouble();
  return double.tryParse(value?.toString() ?? '');
}

bool navivoxBoolFromJson(Object? value, {bool fallback = false}) {
  if (value is bool) return value;
  final text = value?.toString().trim().toLowerCase();
  if (text == 'true' || text == '1' || text == 'yes') return true;
  if (text == 'false' || text == '0' || text == 'no') return false;
  return fallback;
}

/// Returns only literal bool values or `true`/`false` string tokens.
///
/// Use this for protocol flags whose existing contract intentionally does not
/// accept broader truthy aliases such as `1` or `yes`.
bool navivoxStrictBoolFromJson(Object? value, {bool fallback = false}) {
  if (value is bool) return value;
  final text = value?.toString().trim().toLowerCase();
  if (text == 'true') return true;
  if (text == 'false') return false;
  return fallback;
}

Map<String, Object?> navivoxMapFromJson(Object? value) {
  if (value is! Map) return const {};
  return Map<String, Object?>.from(value);
}

Map<String, Object?> navivoxMapFieldFromJson(
  Map<String, Object?> json,
  String key,
) {
  return navivoxMapFromJson(json[key]);
}

List<Object?> navivoxListFromJson(Object? value) {
  if (value is! List) return const [];
  return value.cast<Object?>();
}

/// Returns map entries from a loose wire list, ignoring non-map items.
List<Map<String, Object?>> navivoxMapListFromJson(Object? value) {
  return navivoxListFromJson(
    value,
  ).whereType<Map>().map(navivoxMapFromJson).toList(growable: false);
}

List<Object?> navivoxListFieldFromJson(Map<String, Object?> json, String key) {
  return navivoxListFromJson(json[key]);
}

List<String> navivoxStringListFromJson(Object? value) {
  if (value is! List) return const [];
  return navivoxTrimmedStringList(value);
}

String navivoxStringFieldFromJson(Map<String, Object?> json, String key) {
  return navivoxStringFromJson(json[key], fallback: '');
}

/// Selects a typed enum/value object by matching its wire value.
///
/// The wire token uses the same non-empty trimmed string semantics as other
/// Navivox protocol fields and falls back when the value is blank or unknown.
T navivoxValueFromWire<T>({
  required Object? value,
  required Iterable<T> values,
  required String Function(T value) wireValue,
  required T fallback,
}) {
  final text = navivoxOptionalStringFromJson(value);
  if (text == null) return fallback;
  for (final candidate in values) {
    if (wireValue(candidate) == text) return candidate;
  }
  return fallback;
}

/// Returns the first non-empty literal string field whose key matches [names].
///
/// The lookup first honors exact keys, then falls back to a compatibility match
/// that ignores underscores and case so wire payloads can use either
/// `snake_case` or `camelCase` aliases without each parser reimplementing that
/// policy. Non-string values are intentionally ignored to preserve strict wire
/// semantics for IDs, URLs, and tokens.
String? navivoxFirstStringFieldFromJson(
  Map<dynamic, dynamic> json,
  Iterable<String> names,
) {
  for (final name in names) {
    final exact = navivoxOptionalLiteralStringFromJson(json[name]);
    if (exact != null) return exact;
  }
  final normalizedNames = {
    for (final name in names) _navivoxNormalizeJsonFieldName(name),
  };
  for (final entry in json.entries) {
    if (!normalizedNames.contains(
      _navivoxNormalizeJsonFieldName('${entry.key}'),
    )) {
      continue;
    }
    final value = navivoxOptionalLiteralStringFromJson(entry.value);
    if (value != null) return value;
  }
  return null;
}

String _navivoxNormalizeJsonFieldName(String value) =>
    value.toLowerCase().replaceAll('_', '');

List<String> navivoxStringListFieldFromJson(
  Map<String, Object?> json,
  String key,
) {
  return navivoxStringListFromJson(json[key]);
}

/// Returns non-empty trimmed string values in their original order.
List<String> navivoxTrimmedStringList(Iterable<Object?> values) {
  return values
      .map((item) => item.toString().trim())
      .where((item) => item.isNotEmpty)
      .toList(growable: false);
}

/// Returns a string map with null/blank values removed and remaining values
/// trimmed. Useful for query params and wire request bodies that share Navivox
/// non-empty string field semantics.
Map<String, String> navivoxTrimmedStringFields(Map<String, Object?> values) {
  return {
    for (final entry in values.entries)
      if (entry.value case final value?)
        if (value.toString().trim().isNotEmpty)
          entry.key: value.toString().trim(),
  };
}

DateTime? navivoxDateTimeFromJson(Object? value) {
  final text = value?.toString().trim();
  if (text == null || text.isEmpty) return null;
  return DateTime.tryParse(text);
}

import '../../gateway/client/navivox_gateway_config.dart';
import '../endpoint/navivox_endpoint_uri.dart';
import '../serialization/navivox_json.dart';

class NavivoxPairingDescriptor {
  const NavivoxPairingDescriptor({
    required this.baseUri,
    required this.webSocketUri,
    required this.authMode,
    required this.exposureMode,
    required this.tokenRequired,
    this.token,
    this.serverId,
    this.profileId,
    this.workspaceId,
    this.providerId,
    this.channelIds = const [],
  });

  factory NavivoxPairingDescriptor.parse(String value) {
    final uri = Uri.parse(value.trim());
    if (uri.scheme != 'navivox' || uri.host != 'connect') {
      throw FormatException('Expected navivox://connect descriptor', value);
    }
    final query = uri.queryParameters;
    final tokenRequired = _boolFromPairingParam(query['token_required']);
    final token = _optionalPairingParam(query['rest_token']);
    if (tokenRequired && token == null) {
      throw FormatException('Pairing descriptor requires rest_token', value);
    }
    final webSocketUri = Uri.parse(
      _requiredPairingParam(query, 'websocket_url', value),
    );
    final baseUri = Uri.parse(
      _optionalPairingParam(query['base_url']) ??
          _baseUrlFromWebSocketUri(webSocketUri, value),
    );
    return NavivoxPairingDescriptor(
      baseUri: baseUri,
      webSocketUri: webSocketUri,
      authMode: _optionalPairingParam(query['auth_mode']) ?? '',
      exposureMode: _optionalPairingParam(query['exposure_mode']) ?? '',
      tokenRequired: tokenRequired,
      token: token,
      serverId: _optionalPairingParam(query['server_id']),
      profileId: _optionalPairingParam(query['profile_id']),
      workspaceId: _optionalPairingParam(query['workspace_id']),
      providerId: _optionalPairingParam(query['provider_id']),
      channelIds: _csvPairingParam(query['channel_ids']),
    );
  }

  final Uri baseUri;
  final Uri webSocketUri;
  final String authMode;
  final String exposureMode;
  final bool tokenRequired;
  final String? token;
  final String? serverId;
  final String? profileId;
  final String? workspaceId;
  final String? providerId;
  final List<String> channelIds;

  NavivoxGatewayConfig toGatewayConfig() {
    return NavivoxGatewayConfig(
      baseUri: baseUri,
      token: token,
      webSocketUri: webSocketUri,
    );
  }
}

String _requiredPairingParam(
  Map<String, String> query,
  String name,
  String descriptor,
) {
  final value = _optionalPairingParam(query[name]);
  if (value == null) {
    throw FormatException('Pairing descriptor missing $name', descriptor);
  }
  return value;
}

String? _optionalPairingParam(String? value) {
  return navivoxOptionalStringFromJson(value);
}

String _baseUrlFromWebSocketUri(Uri uri, String descriptor) {
  try {
    return navivoxHttpBaseUrlFromEndpointUri(uri, descriptor: descriptor);
  } on FormatException {
    throw FormatException(
      'Pairing descriptor invalid websocket_url',
      descriptor,
    );
  }
}

bool _boolFromPairingParam(String? value) {
  return navivoxStrictBoolFromJson(value);
}

List<String> _csvPairingParam(String? value) {
  final trimmed = navivoxOptionalStringFromJson(value);
  if (trimmed == null) return const [];
  return navivoxTrimmedStringList(trimmed.split(','));
}

import '../serialization/navivox_json.dart';

/// URI normalization helpers shared by Navivox pairing and setup flows.
const navivoxEndpointSchemes = {'http', 'https', 'ws', 'wss'};

bool navivoxIsEndpointScheme(String scheme) {
  return navivoxEndpointSchemes.contains(scheme.trim().toLowerCase());
}

String navivoxHttpSchemeFromEndpointScheme(
  String scheme, {
  String? descriptor,
}) {
  return switch (scheme.trim().toLowerCase()) {
    'ws' => 'http',
    'wss' => 'https',
    'http' => 'http',
    'https' => 'https',
    _ => throw FormatException(
      'Navivox endpoint URI must use ws, wss, http, or https',
      descriptor,
    ),
  };
}

String navivoxOriginFromUri(Uri uri) {
  final host = uri.host.contains(':') ? '[${uri.host}]' : uri.host;
  final port = uri.hasPort ? ':${uri.port}' : '';
  return '${uri.scheme}://$host$port';
}

String navivoxHttpBaseUrlFromEndpointUri(Uri uri, {String? descriptor}) {
  final scheme = navivoxHttpSchemeFromEndpointScheme(
    uri.scheme,
    descriptor: descriptor,
  );
  if (uri.host.isEmpty) {
    throw FormatException(
      'Navivox endpoint URI must include a host',
      descriptor,
    );
  }
  return navivoxOriginFromUri(uri.replace(scheme: scheme));
}

String? navivoxHttpOriginOrOriginalFromString(String? raw) {
  final value = navivoxOptionalStringFromJson(raw);
  if (value == null) return null;
  final uri = Uri.tryParse(value);
  if (uri == null || !uri.hasScheme || uri.host.isEmpty) return value;
  final scheme = uri.scheme.toLowerCase();
  if (scheme != 'http' && scheme != 'https') return value;
  return navivoxOriginFromUri(uri);
}

String? navivoxWebSocketUrlFromEndpointString(String? raw) {
  final uri = _endpointUriFromString(raw);
  if (uri == null) return null;
  final scheme = uri.scheme.toLowerCase();
  if (scheme != 'ws' && scheme != 'wss') return null;
  return uri.toString();
}

String? navivoxHttpBaseUrlFromEndpointString(String? raw) {
  final uri = _endpointUriFromString(raw);
  if (uri == null || !navivoxIsEndpointScheme(uri.scheme)) return null;
  return navivoxHttpBaseUrlFromEndpointUri(uri);
}

Uri? _endpointUriFromString(String? raw) {
  final value = navivoxOptionalStringFromJson(raw);
  if (value == null) return null;
  final uri = Uri.tryParse(value);
  if (uri == null || !uri.hasScheme || uri.host.isEmpty) return null;
  return uri;
}

import '../serialization/navivox_json.dart';

/// Shared helpers for loose config-schema/validation wire maps.
///
/// Gormes config payloads may identify fields with related aliases depending on
/// whether the source is schema rows, validation errors, or section references.
/// These helpers keep alias lookup and non-empty string coercion consistent
/// across gateway protocol models and UI form models without broadening each
/// call site's accepted aliases.
String? configWireString(Object? raw) => navivoxOptionalStringFromJson(raw);

String? configWireStringFromAliases(Map raw, Iterable<String> aliases) {
  for (final alias in aliases) {
    final text = configWireString(raw[alias]);
    if (text != null) return text;
  }
  return null;
}

import '../serialization/navivox_json.dart';

/// Shared memory-protocol degradation contract.
///
/// Memory overview, search, detail, and action payloads all surface degraded
/// state through the same wire aliases and non-empty reason semantics.
String navivoxMemoryDegradedReasonFromJson(Map<String, Object?> json) {
  return navivoxStringFromJson(
    json['degraded_reason'] ?? json['reason'],
    fallback: '',
  );
}

bool navivoxMemoryIsDegraded(String degradedReason) {
  return degradedReason.trim().isNotEmpty;
}

/// Builds the stable key used to identify a profile contact across channel,
/// routing, and transcript state.
String navivoxProfileContactKey({
  required String serverId,
  required String profileId,
}) {
  return '$serverId::$profileId';
}

/// Builds a profile-contact key from optional wire values.
///
/// Returns null when either side is absent or blank after trimming.
String? navivoxProfileContactKeyFromNullable({
  required String? serverId,
  required String? profileId,
}) {
  final server = serverId?.trim();
  final profile = profileId?.trim();
  if (server == null || server.isEmpty || profile == null || profile.isEmpty) {
    return null;
  }
  return navivoxProfileContactKey(serverId: server, profileId: profile);
}

/// Shared contract for canonical local voice-capture unavailable reasons.
///
/// Gateway state, speech services, voice controllers, and presentation rows all
/// exchange these string reasons. Keep canonicalization here so policy changes
/// do not drift across feature layers.
const deviceSttUnavailableReason = 'device STT unavailable';
const microphonePermissionDeniedReason = 'microphone permission denied';

String? canonicalVoiceUnavailableReason(
  String? reason, {
  bool emptyAsNull = false,
}) {
  final trimmed = reason?.trim();
  if (trimmed == null) return null;
  if (trimmed.isEmpty) return emptyAsNull ? null : trimmed;
  final normalized = trimmed.toLowerCase();
  if (normalized == 'device stt unavailable') return deviceSttUnavailableReason;
  if (normalized == microphonePermissionDeniedReason) {
    return microphonePermissionDeniedReason;
  }
  return trimmed;
}

